import{c as s,Q as e,j as a,m as l}from"./chunks/framework.DVkeSyfh.js";const k=JSON.parse('{"title":"Скрипт восстановления аудиометаданных","description":"","frontmatter":{},"headers":[],"relativePath":"ru/scripts/repair-audio-metadata.md","filePath":"ru/scripts/repair-audio-metadata.md","lastUpdated":1780038170000}'),t={name:"ru/scripts/repair-audio-metadata.md"};function p(d,i,o,r,c,n){return e(),a("div",null,[...i[0]||(i[0]=[l(`<h1 id="скрипт-восстановления-аудиометаданных" tabindex="-1">Скрипт восстановления аудиометаданных <a class="header-anchor" href="#скрипт-восстановления-аудиометаданных" aria-label="Permalink to &quot;Скрипт восстановления аудиометаданных&quot;">​</a></h1><p>По возможности запускайте этот скрипт через проектное Python-окружение:</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.\\.venv\\Scripts\\</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">python.exe</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> scripts\\audio_repair\\repair_audio_metadata.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">help</span></span></code></pre></div><p>Отдельный вспомогательный инструмент для диагностики и восстановления проблем с аудиометаданными и контейнерами. Dry-run работает только на чтение и не копирует и не записывает аудиофайлы. Каждый обычный запуск по умолчанию пишет repair-специфичный JSON-отчёт, оформленную книгу XLSX и структурированный текстовый лог в <code>scripts\\audio_repair\\reports</code>.</p><p>Используйте этот скрипт, когда сканирование, RefreshTags или запись жанров сообщают о подозрительных либо нечитаемых метаданных, особенно для краевых случаев WAV/AIFF/контейнеров. Не используйте его как обычный редактор тегов: это диагностический и repair-инструмент для файлов, которые сам скрипт классифицирует как безопасные для восстановления.</p><p>Использование:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>python scripts\\audio_repair\\repair_audio_metadata.py [OPTIONS] [paths ...]</span></span></code></pre></div><p>Входные данные:</p><ul><li>позиционные <code>paths</code>: аудиофайлы для проверки или восстановления.</li><li><code>--folder FOLDER</code>: рекурсивно собрать поддерживаемые аудиофайлы из папки.</li><li><code>--db DB</code>: собрать существующие аудиофайлы из <code>tracks.path</code> в SQLite-базе библиотеки. База открывается только на чтение.</li><li><code>--db-root PATH</code>: использовать только пути базы данных под этим сохранённым корнем. Можно указывать несколько раз.</li><li><code>--file-root PATH</code>: заменить совпавший префикс <code>--db-root</code> этим реальным корнем файловой системы перед проверкой существования каждого файла.</li><li><code>--log LOG</code>: извлечь из лога проекта пути WAV с post-save readback failure.</li><li><code>--since TIMESTAMP</code>: использовать только строки лога с указанной временной метки и позже.</li><li><code>--until TIMESTAMP</code>: использовать только строки лога раньше указанной временной метки.</li></ul><p>Параметры восстановления и безопасности:</p><ul><li><code>--apply</code>: записать восстановленные файлы. По умолчанию используется dry-run.</li><li><code>--backup-dir PATH</code>: каталог резервных копий, используемый только с <code>--apply</code>.</li><li><code>--no-backup</code>: применить изменения без полных резервных копий файлов; используйте только если есть другая резервная копия.</li><li><code>--keep-id3 first|last|none</code>: для WAV-восстановления выбрать, какой читаемый ID3 chunk верхнего уровня сохранить. По умолчанию <code>first</code>.</li><li><code>--reason VALUE</code>: в folder/db-режиме применять только записи с сохранённой причиной. Можно указывать несколько раз.</li></ul><p>Управление запуском:</p><ul><li><code>--limit N</code>: обработать только первые собранные пути.</li><li><code>--summary-only</code>: вывести только итоговую сводку.</li><li><code>--color auto|always|never</code>: раскрашивать status labels.</li><li><code>--out-dir DIR</code>: каталог отчётов. По умолчанию <code>scripts\\audio_repair\\reports</code>.</li><li><code>--file-log PATH</code>: необязательный лог консольного transcript, который перезаписывается при каждом запуске. Он отделён от структурированного лога отчёта.</li><li><code>--no-file-log</code>: отключить необязательный консольный transcript log.</li><li><code>--no-report</code>: отключить bundle отчётов JSON/XLSX/log.</li><li><code>--state PATH</code>: явный state-файл для folder/db-режима.</li><li><code>--workers N</code>: параллельные воркеры для dry-run. Apply-режим всегда выполняется последовательно.</li></ul><p>Структура, создаваемая по умолчанию:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>scripts\\audio_repair\\reports\\audio_repair_report_&lt;timestamp&gt;.json</span></span>
<span class="line"><span>scripts\\audio_repair\\reports\\audio_repair_report_&lt;timestamp&gt;.xlsx</span></span>
<span class="line"><span>scripts\\audio_repair\\reports\\audio_repair_report_&lt;timestamp&gt;.log</span></span>
<span class="line"><span>scripts\\audio_repair\\state\\state.&lt;source&gt;.&lt;hash&gt;.json</span></span>
<span class="line"><span>scripts\\audio_repair\\backups\\&lt;filename&gt;.&lt;timestamp&gt;.&lt;suffix&gt;.bak</span></span></code></pre></div><p>Bundle отчётов содержит только данные audio-repair. В нём нет группировки дублей, delete candidates, Rhythm Lab impact или полей <code>audio_dedup</code>. JSON хранит собранные источники, параметры запуска, state skips, число отсутствующих DB-файлов, <code>status_counts</code>, <code>reason_counts</code>, <code>problem_summary</code> и один элемент <code>results</code> на обработанный файл. Книга XLSX является основным артефактом для проверки человеком и содержит три листа:</p><ul><li><code>Summary</code>: режим, счётчики источников, число обработанных файлов, state skips, счётчики статусов и счётчики причин.</li><li><code>Results</code>: по одной строке на файл с action (<code>REPAIR AVAILABLE</code>, <code>REPAIRED</code>, <code>REVIEW MANUALLY</code> и так далее), status, reason, path, size delta, ID3 counters, primary action, backup path и Mutagen summary.</li><li><code>Problems</code>: сгруппированная problem summary, соответствующая терминальному выводу.</li></ul><p>Структурированный <code>.log</code> повторяет run-level счётчики в key-value формате для быстрого поиска через grep или shell.</p><p>Рекомендуемый workflow:</p><ol><li>Запустите dry-run на небольшом наборе путей, папке, логе или подмножестве базы данных.</li><li>Просмотрите сгенерированную книгу и status/reason для каждой записи <code>REPAIRABLE</code>.</li><li>Запускайте <code>--apply</code> только для конкретной причины или набора файлов, которые действительно собираетесь исправить.</li><li>Оставляйте backup включённым, если у вас уже нет внешней резервной копии.</li></ol><p>Примеры:</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python scripts\\audio_repair\\repair_audio_metadata.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">folder .\\music </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">workers </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">4</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python scripts\\audio_repair\\repair_audio_metadata.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">folder .\\music </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">apply </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">reason OVERSIZED_DATA</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python scripts\\audio_repair\\repair_audio_metadata.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">db C:\\db\\abstracted.sqlite </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">db</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">root M:\\Volumes\\Abstracted</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python scripts\\audio_repair\\repair_audio_metadata.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">db C:\\db\\abstracted.sqlite </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">db</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">root M:\\Volumes </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">file</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">root S:\\Music\\Volumes</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python scripts\\audio_repair\\repair_audio_metadata.py .\\music\\track.wav </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">summary</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">only</span></span></code></pre></div><p>Значения статусов:</p><ul><li><code>OK</code>: восстановление не требуется.</li><li><code>NOTICE</code>: косметическая необязательная очистка; файл не перезаписывается.</li><li><code>REPAIRABLE</code>: безопасное восстановление существует, но dry-run только сообщает о нём.</li><li><code>REPAIRED</code>: apply-режим записал и проверил восстановление.</li><li><code>SUSPICIOUS</code>: несоответствие формата/контейнера или кодека, требующее более внимательной проверки.</li><li><code>TAG-ERROR</code>: ошибка чтения тегов без безопасного repair-пути.</li><li><code>BROKEN</code>: файл не удалось разобрать как ожидаемый контейнер.</li><li><code>FAILED</code>: apply попытался выполнить repair, но запись или проверка не удалась.</li><li><code>UNSUPPORTED</code>: расширение вне repairable-набора WAV/AIFF; файл только inspected.</li></ul><p>Причины:</p><p>В folder/db-режиме каждый результат также записывает причину в верхнем регистре. Используйте её с <code>--reason</code>, чтобы повторно запустить apply только для одного класса исправлений, например:</p><ul><li><code>OVERSIZED_DATA</code>: WAV chunk <code>data</code> больше аудиополезной нагрузки перед ID3.</li><li><code>DUPLICATE_ID3</code>: больше одного top-level ID3 chunk в WAV.</li><li><code>EMPTY_ID3</code>: пустой AIFF chunk <code>ID3 </code>, блокирующий чтение Mutagen.</li><li><code>CONTAINER_NORMALIZATION</code>: нормализация root-size или padding RIFF/FORM.</li><li><code>EXTENSION_MISMATCH</code>: контейнер/кодек не соответствует расширению файла.</li></ul><p><code>--reason</code> допустим только в folder/db-режиме, потому что требует state-файл. Используйте точный текст причины, показанный в отчёте.</p><p>Коды выхода:</p><ul><li><code>0</code>: завершено без результатов <code>FAILED</code>.</li><li><code>1</code>: хотя бы один файл завершился статусом <code>FAILED</code>.</li><li><code>2</code>: ошибка использования, например <code>--file-root</code> без <code>--db-root</code>, <code>--reason</code> вне state-режима, <code>--backup-dir</code> вместе с <code>--no-backup</code> или отсутствие входных путей.</li></ul>`,30)])])}const E=s(t,[["render",p]]);export{k as __pageData,E as default};
